fun solve(landStartTime: Array<Long>, landDuration: Array<Long>, waterStartTime: Array<Long>, waterDuration: Array<Long>): Long {
    // Case 1: Land first, then Water
    val m = waterStartTime.size
    val waterList = waterStartTime.indices.map { i ->
        waterStartTime[i] to waterDuration[i]
    }.sortedBy { it.first }
    val waterStarts = waterList.map { it.first }.toLongArray()
    val waterEnds = waterList.map { it.first + it.second }.toLongArray()
    val waterSuffixMin = LongArray(m + 1) { Long.MAX_VALUE }
    for (i in m - 1 downTo 0) {
        waterSuffixMin[i] = minOf(waterEnds[i], waterSuffixMin[i + 1])
    }
    val waterDurations = waterList.map { it.second }.toLongArray()
    val waterPrefixMinDur = if (m > 0) {
        LongArray(m).apply {
            this[0] = waterDurations[0]
            for (i in 1 until m) {
                this[i] = minOf(this[i - 1], waterDurations[i])
            }
        }
    } else {
        LongArray(0)
    }

    fun fWater(x: Long): Long {
        val lbIdx = waterStarts.binarySearch(x)
        val lb = if (lbIdx >= 0) lbIdx else -lbIdx - 1
        var optionA = Long.MAX_VALUE
        if (lb < m) {
            optionA = waterSuffixMin[lb]
        }
        var optionB = Long.MAX_VALUE
        if (lb > 0) {
            optionB = x + waterPrefixMinDur[lb - 1]
        }
        return minOf(optionA, optionB)
    }

    var ans1 = Long.MAX_VALUE
    for (i in landStartTime.indices) {
        val landEnd = landStartTime[i] + landDuration[i]
        ans1 = minOf(ans1, fWater(landEnd))
    }

    // Case 2: Water first, then Land
    val n = landStartTime.size
    val landList = landStartTime.indices.map { i ->
        landStartTime[i] to landDuration[i]
    }.sortedBy { it.first }
    val landStarts = landList.map { it.first }.toLongArray()
    val landEnds = landList.map { it.first + it.second }.toLongArray()
    val landSuffixMin = LongArray(n + 1) { Long.MAX_VALUE }
    for (i in n - 1 downTo 0) {
        landSuffixMin[i] = minOf(landEnds[i], landSuffixMin[i + 1])
    }
    val landDurations = landList.map { it.second }.toLongArray()
    val landPrefixMinDur = if (n > 0) {
        LongArray(n).apply {
            this[0] = landDurations[0]
            for (i in 1 until n) {
                this[i] = minOf(this[i - 1], landDurations[i])
            }
        }
    } else {
        LongArray(0)
    }

    fun gLand(y: Long): Long {
        val lbIdx = landStarts.binarySearch(y)
        val lb = if (lbIdx >= 0) lbIdx else -lbIdx - 1
        var optionA = Long.MAX_VALUE
        if (lb < n) {
            optionA = landSuffixMin[lb]
        }
        var optionB = Long.MAX_VALUE
        if (lb > 0) {
            optionB = y + landPrefixMinDur[lb - 1]
        }
        return minOf(optionA, optionB)
    }

    var ans2 = Long.MAX_VALUE
    for (j in waterStartTime.indices) {
        val waterEnd = waterStartTime[j] + waterDuration[j]
        ans2 = minOf(ans2, gLand(waterEnd))
    }

    return minOf(ans1, ans2)
}
